			return nil, fmt.Errorf("invalid relay credentials TTL %q: %w", relays.CredentialsTTL, err)
		}
	}
	return &nbconfig.Relay{
		Addresses:      relays.Addresses,
		CredentialsTTL: util.Duration{Duration: ttl},
		Secret:         relays.Secret,
	}, nil
}

