1	package explain
2	
3	import (
4		"bytes"
5		"context"
6		"encoding/json"
7		"fmt"
8		"io"
9		"net/http"
10	)
11	
12	const (
13		anthropicDefaultModel = "claude-sonnet-4-20250514"
14		anthropicAPIURL       = "https://api.anthropic.com/v1/messages"
15		anthropicMaxTokens    = 4096
16		anthropicMaxToolLoops = 10
17	)
18	
19	// AnthropicConfig configures the Anthropic provider.
20	type AnthropicConfig struct {
21		APIKey     string
22		Model      string
23		Tools      []Tool
24		McpServers []McpServer
25		HTTPClient HTTPClient
26	}
27	
28	type anthropicProvider struct {
29		apiKey     string
30		model      string
31		tools      []Tool
32		mcpServers []McpServer
33		httpClient HTTPClient
34	}
35	
36	// NewAnthropicProvider returns a Provider backed by the Anthropic Messages API.
37	func NewAnthropicProvider(cfg AnthropicConfig) Provider {
38		model := cfg.Model
39		if model == "" {
40			model = anthropicDefaultModel
41		}
42		client := cfg.HTTPClient
43		if client == nil {
44			client = http.DefaultClient
45		}
46		return &anthropicProvider{
47			apiKey:     cfg.APIKey,
48			model:      model,
49			tools:      cfg.Tools,
50			mcpServers: cfg.McpServers,
51			httpClient: client,
52		}
53	}
54	
55	func (p *anthropicProvider) Complete(ctx context.Context, messages []Message) (string, error) {
56		anthMsgs := make([]map[string]any, 0, len(messages))
57		var systemParts []string
58	
59		for _, m := range messages {
60			switch m.Role {
61			case RoleSystem:
62				systemParts = append(systemParts, m.Content)
63			case RoleContext:
64				anthMsgs = append(anthMsgs, map[string]any{
65					"role":    "user",
66					"content": "[Context]: " + m.Content,
67				})
68			default:
69				anthMsgs = append(anthMsgs, map[string]any{
70					"role":    string(m.Role),
71					"content": m.Content,
72				})
73			}
74		}
75	
76		var toolDefs []map[string]any
77		for _, t := range p.tools {
78			toolDefs = append(toolDefs, map[string]any{
79				"name":         t.Name,
80				"description":  t.Description,
81				"input_schema": json.RawMessage(t.InputSchema),
82			})
83		}
84	
85		var mcpServerDefs []map[string]any
86		for _, mcp := range p.mcpServers {
87			entry := map[string]any{
88				"type": "url",
89				"url":  mcp.URL,
90				"name": mcp.Name,
91			}
92			if mcp.AuthorizationToken != "" {
93				entry["authorization_token"] = mcp.AuthorizationToken
94			}
95			mcpServerDefs = append(mcpServerDefs, entry)
96	
97			// Add a corresponding mcp_toolset tool entry
98			toolDefs = append(toolDefs, map[string]any{
99				"type":            "mcp_toolset",
100				"mcp_server_name": mcp.Name,
101			})
102		}
103	
104		toolsByName := make(map[string]*Tool, len(p.tools))
105		for i := range p.tools {
106			toolsByName[p.tools[i].Name] = &p.tools[i]
107		}
108	
109		var lastTextResponse string
110	
111		for loop := 0; loop < anthropicMaxToolLoops; loop++ {
112			body := map[string]any{
113				"model":      p.model,
114				"max_tokens": anthropicMaxTokens,
115				"messages":   anthMsgs,
116			}
117			if len(systemParts) > 0 {
118				system := ""
119				for i, s := range systemParts {
120					if i > 0 {
121						system += "\n\n"
122					}
123					system += s
124				}
125				body["system"] = system
126			}
127			if len(toolDefs) > 0 {
128				body["tools"] = toolDefs
129			}
130			if len(mcpServerDefs) > 0 {
131				body["mcp_servers"] = mcpServerDefs
132			}
133	
134			headers := map[string]string{
135				"Content-Type":     "application/json",
136				"x-api-key":        p.apiKey,
137				"anthropic-version": "2023-06-01",
138			}
139			if len(p.mcpServers) > 0 {
140				headers["anthropic-beta"] = "mcp-client-2025-11-20"
141			}
142	
143			data, err := p.doRequest(ctx, headers, body)
144			if err != nil {
145				return "", err
146			}
147	
148			// Extract text from content blocks
149			if content, ok := data["content"].([]any); ok {
150				for _, block := range content {
151					bm, ok := block.(map[string]any)
152					if !ok {
153						continue
154					}
155					if bm["type"] == "text" {
156						if text, ok := bm["text"].(string); ok {
157							lastTextResponse = text
158						}
159					}
160				}
161			}
162	
163			stopReason, _ := data["stop_reason"].(string)
164	
165			// MCP pause — re-send with assistant content to continue
166			if stopReason == "pause_turn" {
167				anthMsgs = append(anthMsgs, map[string]any{
168					"role":    "assistant",
169					"content": data["content"],
170				})
171				continue
172			}
173	
174			if stopReason != "tool_use" {
175				if lastTextResponse == "" {
176					return "", fmt.Errorf("no text content in Anthropic response")
177				}
178				return lastTextResponse, nil
179			}
180	
181			// Handle tool calls
182			content, _ := data["content"].([]any)
183			anthMsgs = append(anthMsgs, map[string]any{
184				"role":    "assistant",
185				"content": content,
186			})
187	
188			var toolResults []map[string]any
189			for _, block := range content {
190				bm, ok := block.(map[string]any)
191				if !ok {
192					continue
193				}
194				if bm["type"] != "tool_use" {
195					continue
196				}
197				toolID, _ := bm["id"].(string)
198				toolName, _ := bm["name"].(string)
199	
200				tool, exists := toolsByName[toolName]
201				if !exists {
202					toolResults = append(toolResults, map[string]any{
203						"type":        "tool_result",
204						"tool_use_id": toolID,
205						"content":     fmt.Sprintf("Error: unknown tool %q", toolName),
206					})
207					continue
208				}
209	
210				inputBytes, err := json.Marshal(bm["input"])
211				if err != nil {
212					toolResults = append(toolResults, map[string]any{
213						"type":        "tool_result",
214						"tool_use_id": toolID,
215						"content":     fmt.Sprintf("Error: %s", err),
216					})
217					continue
218				}
219	
220				result, err := tool.Execute(inputBytes)
221				if err != nil {
222					toolResults = append(toolResults, map[string]any{
223						"type":        "tool_result",
224						"tool_use_id": toolID,
225						"content":     fmt.Sprintf("Error: %s", err),
226					})
227					continue
228				}
229	
230				toolResults = append(toolResults, map[string]any{
231					"type":        "tool_result",
232					"tool_use_id": toolID,
233					"content":     result,
234				})
235			}
236	
237			anthMsgs = append(anthMsgs, map[string]any{
238				"role":    "user",
239				"content": toolResults,
240			})
241		}
242	
243		if lastTextResponse != "" {
244			return lastTextResponse, nil
245		}
246		return "", fmt.Errorf("anthropic tool loop exceeded maximum iterations")
247	}
248	
249	func (p *anthropicProvider) doRequest(ctx context.Context, headers map[string]string, body map[string]any) (map[string]any, error) {
250		bodyBytes, err := json.Marshal(body)
251		if err != nil {
252			return nil, fmt.Errorf("marshal request: %w", err)
253		}
254	
255		req, err := http.NewRequestWithContext(ctx, http.MethodPost, anthropicAPIURL, bytes.NewReader(bodyBytes))
256		if err != nil {
257			return nil, fmt.Errorf("create request: %w", err)
258		}
259		for k, v := range headers {
260			req.Header.Set(k, v)
261		}
262	
263		resp, err := p.httpClient.Do(req)
264		if err != nil {
265			return nil, fmt.Errorf("anthropic request: %w", err)
266		}
267		defer resp.Body.Close()
268	
269		respBody, err := io.ReadAll(resp.Body)
270		if err != nil {
271			return nil, fmt.Errorf("read response: %w", err)
272		}
273	
274		if resp.StatusCode != http.StatusOK {
275			return nil, fmt.Errorf("Anthropic API error %d: %s", resp.StatusCode, string(respBody))
276		}
277	
278		var data map[string]any
279		if err := json.Unmarshal(respBody, &data); err != nil {
280			return nil, fmt.Errorf("decode response: %w", err)
281		}
282		return data, nil
283	}

