package main

import (
	"flag"
	"fmt"
	"log"
	"net/http"
	"os"

	"gopkg.in/yaml.v3"

	"github.com/netbirdio/netbird/explain"
)

type mcpServerConfig struct {
	Name               string `yaml:"name"`
	URL                string `yaml:"url"`
	AuthorizationToken string `yaml:"authorization_token"`
}

type config struct {
	Listen       string            `yaml:"listen"`
	BearerToken  string            `yaml:"bearer_token"`
	Provider     string            `yaml:"provider"`
	APIKey       string            `yaml:"api_key"`
	Model        string            `yaml:"model"`
	BaseURL      string            `yaml:"base_url"`
	SystemPrompt string            `yaml:"system_prompt"`
	McpServers   []mcpServerConfig `yaml:"mcp_servers"`
}

func main() {
	configPath := flag.String("config", "config.yaml", "path to YAML config file")
	flag.Parse()

	cfg, err := loadConfig(*configPath)
	if err != nil {
		log.Fatalf("load config: %v", err)
	}

	if cfg.APIKey == "" {
		log.Fatal("api_key is required in config")
	}
	if cfg.Listen == "" {
		cfg.Listen = ":8080"
	}
	if cfg.Provider == "" {
		cfg.Provider = "anthropic"
	}

	p, err := newProvider(cfg)
	if err != nil {
		log.Fatal(err)
	}

	handler := explain.NewHandler(explain.Config{
		Provider:     p,
		BearerToken:  cfg.BearerToken,
		SystemPrompt: cfg.SystemPrompt,
	})

	mux := http.NewServeMux()
	mux.Handle("/api/ai/chat", handler)

	log.Printf("listening on %s", cfg.Listen)
	if err := http.ListenAndServe(cfg.Listen, mux); err != nil {
		log.Fatal(err)
	}
}

func loadConfig(path string) (*config, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("read %s: %w", path, err)
	}
	var cfg config
	if err := yaml.Unmarshal(data, &cfg); err != nil {
		return nil, fmt.Errorf("parse %s: %w", path, err)
	}
	return &cfg, nil
}

func newProvider(cfg *config) (explain.Provider, error) {
	switch cfg.Provider {
	case "anthropic":
		var mcpServers []explain.McpServer
		for _, m := range cfg.McpServers {
			mcpServers = append(mcpServers, explain.McpServer{
				Name:               m.Name,
				URL:                m.URL,
				AuthorizationToken: m.AuthorizationToken,
			})
		}
		return explain.NewAnthropicProvider(explain.AnthropicConfig{
			APIKey:     cfg.APIKey,
			Model:      cfg.Model,
			McpServers: mcpServers,
		}), nil
	case "openai":
		return explain.NewOpenAIProvider(explain.OpenAIConfig{
			APIKey: cfg.APIKey,
			Model:  cfg.Model,
		}), nil
	case "dify":
		if cfg.BaseURL == "" {
			return nil, fmt.Errorf("base_url is required for the dify provider")
		}
		return explain.NewDifyProvider(explain.DifyConfig{
			APIKey:  cfg.APIKey,
			BaseURL: cfg.BaseURL,
		}), nil
	default:
		return nil, fmt.Errorf("unknown provider: %s", cfg.Provider)
	}
}

