package rag

import (
	"bufio"
	"fmt"
	"os"
	"path/filepath"
	"strings"
)

// Chunk represents a section of a documentation file.
type Chunk struct {
	// Source is the relative path to the source file.
	Source string
	// Heading is the section heading (e.g. "## Installation").
	Heading string
	// Body is the text content of the section.
	Body string
}

// ID returns a stable identifier for the chunk.
func (c Chunk) ID() string {
	return fmt.Sprintf("%s#%s", c.Source, c.Heading)
}

// ChunkMarkdownFile splits a single markdown file into chunks by heading.
// Each chunk contains the heading and the body text until the next heading
// of equal or higher level.
func ChunkMarkdownFile(path, relPath string) ([]Chunk, error) {
	f, err := os.Open(path)
	if err != nil {
		return nil, err
	}
	defer f.Close()

	var chunks []Chunk
	var currentHeading string
	var currentBody strings.Builder

	flush := func() {
		body := strings.TrimSpace(currentBody.String())
		if body == "" && currentHeading == "" {
			return
		}
		chunks = append(chunks, Chunk{
			Source:  relPath,
			Heading: currentHeading,
			Body:    body,
		})
	}

	scanner := bufio.NewScanner(f)
	for scanner.Scan() {
		line := scanner.Text()
		if isHeading(line) {
			flush()
			currentHeading = strings.TrimSpace(strings.TrimLeft(line, "#"))
			currentBody.Reset()
		} else {
			currentBody.WriteString(line)
			currentBody.WriteString("\n")
		}
	}
	if err := scanner.Err(); err != nil {
		return nil, err
	}

	flush()
	return chunks, nil
}

// ChunkDirectory walks a directory and chunks all .md and .mdx files.
func ChunkDirectory(root string) ([]Chunk, error) {
	var all []Chunk
	err := filepath.Walk(root, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}
		if info.IsDir() {
			return nil
		}
		ext := strings.ToLower(filepath.Ext(path))
		if ext != ".md" && ext != ".mdx" {
			return nil
		}
		rel, _ := filepath.Rel(root, path)
		chunks, err := ChunkMarkdownFile(path, rel)
		if err != nil {
			return fmt.Errorf("chunk %s: %w", rel, err)
		}
		all = append(all, chunks...)
		return nil
	})
	return all, err
}

func isHeading(line string) bool {
	return strings.HasPrefix(line, "# ") ||
		strings.HasPrefix(line, "## ") ||
		strings.HasPrefix(line, "### ") ||
		strings.HasPrefix(line, "#### ")
}

package rag

import (
	"fmt"

	"github.com/blevesearch/bleve/v2"
)

// document is the structure indexed by bleve.
type document struct {
	Source  string `json:"source"`
	Heading string `json:"heading"`
	Body    string `json:"body"`
}

// BuildIndex creates a new bleve index at indexPath from the given chunks.
// It overwrites any existing index at that path.
func BuildIndex(indexPath string, chunks []Chunk) (int, error) {
	mapping := bleve.NewIndexMapping()
	index, err := bleve.New(indexPath, mapping)
	if err != nil {
		return 0, fmt.Errorf("create index: %w", err)
	}
	defer index.Close()

	batch := index.NewBatch()
	for _, c := range chunks {
		doc := document{
			Source:  c.Source,
			Heading: c.Heading,
			Body:    c.Body,
		}
		batch.Index(c.ID(), doc)
	}

	if err := index.Batch(batch); err != nil {
		return 0, fmt.Errorf("index batch: %w", err)
	}

	return len(chunks), nil
}

// SearchResult holds a single search hit.
type SearchResult struct {
	Source  string
	Heading string
	Body    string
	Score   float64
}

// Search opens an existing bleve index and returns the top-k results for the query.
func Search(indexPath string, query string, topK int) ([]SearchResult, error) {
	index, err := bleve.Open(indexPath)
	if err != nil {
		return nil, fmt.Errorf("open index: %w", err)
	}
	defer index.Close()

	q := bleve.NewMatchQuery(query)
	req := bleve.NewSearchRequestOptions(q, topK, 0, false)
	req.Fields = []string{"source", "heading", "body"}

	res, err := index.Search(req)
	if err != nil {
		return nil, fmt.Errorf("search: %w", err)
	}

	var results []SearchResult
	for _, hit := range res.Hits {
		results = append(results, SearchResult{
			Source:  str(hit.Fields["source"]),
			Heading: str(hit.Fields["heading"]),
			Body:    str(hit.Fields["body"]),
			Score:   hit.Score,
		})
	}
	return results, nil
}

func str(v interface{}) string {
	s, _ := v.(string)
	return s
}

