// Command index builds a bleve full-text search index from a directory of
// markdown documentation files.
//
// Usage:
//
//	go run ./explain/cmd/index -docs ./docs -index ./explain/cmd/docs.bleve
package main

import (
	"flag"
	"log"
	"os"

	"github.com/netbirdio/netbird/explain/rag"
)

func main() {
	docsDir := flag.String("docs", "", "path to the documentation directory (required)")
	indexPath := flag.String("index", "docs.bleve", "path for the output bleve index")
	flag.Parse()

	if *docsDir == "" {
		flag.Usage()
		os.Exit(1)
	}

	// Remove existing index so we do a full rebuild.
	if err := os.RemoveAll(*indexPath); err != nil {
		log.Fatalf("remove old index: %v", err)
	}

	log.Printf("chunking markdown files in %s ...", *docsDir)
	chunks, err := rag.ChunkDirectory(*docsDir)
	if err != nil {
		log.Fatalf("chunk: %v", err)
	}
	log.Printf("found %d chunks", len(chunks))

	log.Printf("building index at %s ...", *indexPath)
	n, err := rag.BuildIndex(*indexPath, chunks)
	if err != nil {
		log.Fatalf("build index: %v", err)
	}
	log.Printf("indexed %d documents", n)
}

