package rag

import (
	"context"
	"fmt"
	"log"
	"strings"

	"github.com/netbirdio/netbird/explain"
)

// MiddlewareConfig configures the RAG middleware.
type MiddlewareConfig struct {
	// IndexPath is the path to the bleve index directory.
	IndexPath string
	// TopK is the number of chunks to retrieve per query.
	TopK int
}

// NewMiddleware returns an explain.Middleware that enriches messages with
// relevant documentation chunks retrieved via BM25 full-text search.
func NewMiddleware(cfg MiddlewareConfig) explain.Middleware {
	topK := cfg.TopK
	if topK <= 0 {
		topK = 5
	}

	return func(ctx context.Context, messages []explain.Message, next func(context.Context, []explain.Message) (string, error)) (string, error) {
		query := extractQuery(messages)
		if query == "" {
			return next(ctx, messages)
		}

		results, err := Search(cfg.IndexPath, query, topK)
		if err != nil {
			log.Printf("[rag] search error: %v", err)
			return next(ctx, messages)
		}

		if len(results) == 0 {
			log.Printf("[rag] query=%q no results found", query)
			return next(ctx, messages)
		}

		log.Printf("[rag] query=%q matched %d chunks:", query, len(results))
		for i, r := range results {
			log.Printf("[rag]   %d. score=%.2f  %s | %s", i+1, r.Score, r.Source, r.Heading)
		}

		contextMsg := explain.Message{
			Role:    explain.RoleContext,
			Content: formatResults(results),
		}

		enriched := make([]explain.Message, 0, len(messages)+1)
		// Insert context after any system messages but before user messages.
		inserted := false
		for _, m := range messages {
			if !inserted && m.Role != explain.RoleSystem {
				enriched = append(enriched, contextMsg)
				inserted = true
			}
			enriched = append(enriched, m)
		}
		if !inserted {
			enriched = append(enriched, contextMsg)
		}

		return next(ctx, enriched)
	}
}

// extractQuery pulls the last user message as the search query.
func extractQuery(messages []explain.Message) string {
	for i := len(messages) - 1; i >= 0; i-- {
		if messages[i].Role == explain.RoleUser {
			return messages[i].Content
		}
	}
	return ""
}

func formatResults(results []SearchResult) string {
	var b strings.Builder
	b.WriteString("Relevant documentation:\n\n")
	for i, r := range results {
		fmt.Fprintf(&b, "---\nSource: %s\nSection: %s\n\n%s\n", r.Source, r.Heading, r.Body)
		if i < len(results)-1 {
			b.WriteString("\n")
		}
	}
	return b.String()
}

